INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'ed', 7, 1, NULL, 'Thomas Goodwin em Ed 7:1', 'Thomas Goodwin interpreta este versículo a partir de a piedade prática e a santificação do coração. Em Esdras 7, Deus revela providência divina na história do povo de Deus de forma pastoral e transformadora, promovendo santidade prática. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Thomas Goodwin', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'ed', 8, 1, NULL, 'Alexander Maclaren em Ed 8:1', 'Alexander Maclaren destaca a coerência doutrinária aplicada à vida cristã. Em Esdras 8, o foco recai sobre providência divina na história do povo de Deus e chama a igreja para justiça com misericórdia. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Alexander Maclaren', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'ed', 9, 1, NULL, 'Basílio de Cesareia em Ed 9:1', 'Na leitura de Basílio de Cesareia, vemos a leitura cristológica e eclesial da passagem. Esdras 9 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Basílio de Cesareia', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'ed', 10, 1, NULL, 'Stephen Charnock em Ed 10:1', 'Segundo Stephen Charnock, a piedade prática e a santificação do coração ilumina o sentido deste texto. Esdras 10 mostra que providência divina na história do povo de Deus sustenta a caminhada da fé, especialmente em amor fraternal. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Stephen Charnock', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'ne', 1, 1, NULL, 'Anselmo de Cantuária em Ne 1:1', 'Na leitura de Anselmo de Cantuária, vemos a síntese entre fé, razão e vida santa. Neemias 1 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Anselmo de Cantuária', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'ne', 2, 1, NULL, 'William Perkins em Ne 2:1', 'Segundo William Perkins, a piedade prática e a santificação do coração ilumina o sentido deste texto. Neemias 2 mostra que providência divina na história do povo de Deus sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'William Perkins', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'ne', 3, 1, NULL, 'B. B. Warfield em Ne 3:1', 'Na leitura de B. B. Warfield, vemos a coerência doutrinária aplicada à vida cristã. Neemias 3 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'B. B. Warfield', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'ne', 4, 1, NULL, 'Tomás de Aquino em Ne 4:1', 'Tomás de Aquino interpreta este versículo a partir de a síntese entre fé, razão e vida santa. Em Neemias 4, Deus revela providência divina na história do povo de Deus de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Tomás de Aquino', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'ne', 5, 1, NULL, 'Thomas Goodwin em Ne 5:1', 'Thomas Goodwin destaca a piedade prática e a santificação do coração. Em Neemias 5, o foco recai sobre providência divina na história do povo de Deus e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Thomas Goodwin', 'commentary', '#2E8B57', NOW()),
